{
  "name": "La Cantina Digital - Modern Mexican Ordering",
  "description": "A full-featured Mexican restaurant web application with online ordering, modifiers, admin dashboard, and AI-powered upsell suggestions using Gemini.",
  "requestFramePermissions": [
    "geolocation"
  ]
}

export type Category = 'Tacos' | 'Burritos' | 'Tortas' | 'Sides' | 'Drinks' | 'Desserts' | 'Specials';

export interface Modifier {
  id: string;
  name: string;
  price: number;
}

export interface MenuItem {
  id: string;
  name: string;
  description: string;
  price: number;
  category: Category;
  image: string;
  availableModifiers: Modifier[];
}

export interface CartItem extends MenuItem {
  cartId: string;
  quantity: number;
  selectedModifiers: Modifier[];
  specialInstructions?: string;
}

export interface Order {
  id: string;
  items: CartItem[];
  total: number;
  status: 'pending' | 'preparing' | 'ready' | 'delivered' | 'cancelled';
  customerName: string;
  deliveryType: 'pickup' | 'delivery';
  address?: string;
  timestamp: number;
}

import { GoogleGenAI, Type } from "@google/genai";
import { CartItem, MenuItem } from "../types";

export const getUpsellSuggestions = async (cart: CartItem[], menu: MenuItem[]): Promise<string> => {
  if (cart.length === 0) return "Add some delicious tacos to start!";

  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const cartNames = cart.map(item => item.name).join(", ");
  const menuSummary = menu.map(item => `${item.name} (${item.category})`).join(", ");

  const prompt = `You are an AI waiter at 'La Cantina Digital', a Mexican restaurant. 
  Current cart: [${cartNames}]. 
  Available items to suggest from: [${menuSummary}].

  Based on what the customer has in their cart, suggest ONE or TWO items they might want to add (e.g. if they have tacos, suggest a drink or dessert). 
  Keep it short, friendly, and persuasive. Max 20 words.`;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        temperature: 0.7,
      }
    });
    return response.text || "Would you like some fresh chips and guacamole with that?";
  } catch (error) {
    console.error("AI Error:", error);
    return "Complete your meal with a refreshing Horchata!";
  }
};

