import React, { useState } from 'react';
import { MenuItem, Modifier } from '../types';
import { Plus, X, ChevronRight } from 'lucide-react';

interface MenuCardProps {
  item: MenuItem;
  onAddToCart: (item: MenuItem, modifiers: Modifier[], quantity: number) => void;
}

const MenuCard: React.FC<MenuCardProps> = ({ item, onAddToCart }) => {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [selectedMods, setSelectedMods] = useState<Modifier[]>([]);
  const [quantity, setQuantity] = useState(1);

  const handleToggleMod = (mod: Modifier) => {
    setSelectedMods(prev => 
      prev.find(m => m.id === mod.id)
        ? prev.filter(m => m.id !== mod.id)
        : [...prev, mod]
    );
  };

  const handleAdd = () => {
    onAddToCart(item, selectedMods, quantity);
    setIsModalOpen(false);
    setSelectedMods([]);
    setQuantity(1);
  };

  const totalPrice = item.price + selectedMods.reduce((acc, curr) => acc + curr.price, 0);

  return (
    <>
      <div 
        onClick={() => setIsModalOpen(true)}
        className="group bg-white rounded-2xl overflow-hidden shadow-sm hover:shadow-md transition-all cursor-pointer border border-stone-100"
      >
        <div className="relative h-48 overflow-hidden">
          <img 
            src={item.image} 
            alt={item.name} 
            className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-500"
          />
          <div className="absolute top-3 right-3 bg-white/90 backdrop-blur-sm px-3 py-1 rounded-full text-sm font-bold text-orange-600 shadow-sm">
            ${item.price.toFixed(2)}
          </div>
        </div>
        <div className="p-4">
          <h3 className="text-lg font-bold text-stone-800 mb-1">{item.name}</h3>
          <p className="text-stone-500 text-sm line-clamp-2 mb-3 leading-relaxed">
            {item.description}
          </p>
          <div className="flex items-center justify-between">
            <span className="text-xs font-semibold uppercase tracking-wider text-stone-400">{item.category}</span>
            <button className="p-1.5 bg-orange-500 hover:bg-orange-600 text-white rounded-lg transition-colors">
              <Plus className="h-5 w-5" />
            </button>
          </div>
        </div>
      </div>

      {isModalOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-stone-900/40 backdrop-blur-sm">
          <div className="bg-white rounded-3xl w-full max-w-md overflow-hidden shadow-2xl animate-in fade-in zoom-in duration-200">
            <div className="relative h-56">
              <img src={item.image} alt={item.name} className="w-full h-full object-cover" />
              <button 
                onClick={() => setIsModalOpen(false)}
                className="absolute top-4 right-4 p-2 bg-white/20 hover:bg-white/40 backdrop-blur-md rounded-full text-white transition-colors"
              >
                <X className="h-6 w-6" />
              </button>
            </div>

            <div className="p-6">
              <div className="flex justify-between items-start mb-4">
                <div>
                  <h2 className="text-2xl font-bold text-stone-800">{item.name}</h2>
                  <p className="text-stone-500 text-sm mt-1">{item.description}</p>
                </div>
                <div className="text-xl font-bold text-orange-600">${item.price.toFixed(2)}</div>
              </div>

              {item.availableModifiers.length > 0 && (
                <div className="mb-6">
                  <h4 className="text-sm font-bold text-stone-400 uppercase tracking-widest mb-3">Customizations</h4>
                  <div className="space-y-2">
                    {item.availableModifiers.map(mod => (
                      <label 
                        key={mod.id}
                        className="flex items-center justify-between p-3 rounded-xl border border-stone-100 hover:bg-orange-50 transition-colors cursor-pointer group"
                      >
                        <div className="flex items-center gap-3">
                          <input 
                            type="checkbox" 
                            className="w-5 h-5 accent-orange-500 rounded-md"
                            checked={selectedMods.some(m => m.id === mod.id)}
                            onChange={() => handleToggleMod(mod)}
                          />
                          <span className="text-stone-700 font-medium">{mod.name}</span>
                        </div>
                        {mod.price > 0 && (
                          <span className="text-sm font-bold text-stone-400">+${mod.price.toFixed(2)}</span>
                        )}
                      </label>
                    ))}
                  </div>
                </div>
              )}

              <div className="flex items-center gap-4 pt-4 border-t border-stone-100">
                <div className="flex items-center border border-stone-200 rounded-xl overflow-hidden">
                  <button 
                    disabled={quantity <= 1}
                    onClick={() => setQuantity(q => q - 1)}
                    className="p-3 hover:bg-stone-50 disabled:opacity-30"
                  >-</button>
                  <span className="px-4 font-bold min-w-[3rem] text-center">{quantity}</span>
                  <button 
                    onClick={() => setQuantity(q => q + 1)}
                    className="p-3 hover:bg-stone-50"
                  >+</button>
                </div>
                <button 
                  onClick={handleAdd}
                  className="flex-1 bg-orange-600 hover:bg-orange-700 text-white font-bold py-4 rounded-xl shadow-lg shadow-orange-200 flex items-center justify-center gap-2 transition-all active:scale-95"
                >
                  Add to Cart — ${(totalPrice * quantity).toFixed(2)}
                  <ChevronRight className="h-5 w-5" />
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </>
  );
};

export default MenuCard;

import React, { useEffect, useState } from 'react';
import { CartItem, MenuItem } from '../types';
import { X, Trash2, Sparkles, MapPin, ShoppingBag } from 'lucide-react';
import { getUpsellSuggestions } from '../services/geminiService';

interface CartProps {
  isOpen: boolean;
  onClose: () => void;
  items: CartItem[];
  onRemove: (cartId: string) => void;
  onUpdateQuantity: (cartId: string, delta: number) => void;
  onCheckout: (deliveryType: 'pickup' | 'delivery') => void;
  menu: MenuItem[];
}

const Cart: React.FC<CartProps> = ({ isOpen, onClose, items, onRemove, onUpdateQuantity, onCheckout, menu }) => {
  const [upsell, setUpsell] = useState<string>("");
  const [loadingUpsell, setLoadingUpsell] = useState(false);
  const [deliveryType, setDeliveryType] = useState<'pickup' | 'delivery'>('pickup');

  useEffect(() => {
    if (isOpen && items.length > 0) {
      setLoadingUpsell(true);
      getUpsellSuggestions(items, menu).then(suggestion => {
        setUpsell(suggestion);
        setLoadingUpsell(false);
      });
    }
  }, [isOpen, items.length]);

  const subtotal = items.reduce((acc, item) => {
    const modsTotal = item.selectedModifiers.reduce((sum, m) => sum + m.price, 0);
    return acc + (item.price + modsTotal) * item.quantity;
  }, 0);

  const deliveryFee = deliveryType === 'delivery' ? 4.99 : 0;
  const total = subtotal + deliveryFee;

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-[110] overflow-hidden">
      <div className="absolute inset-0 bg-stone-900/40 backdrop-blur-sm" onClick={onClose} />
      <div className="absolute right-0 top-0 h-full w-full max-w-md bg-stone-50 shadow-2xl animate-in slide-in-from-right duration-300">
        <div className="flex flex-col h-full">
          {/* Header */}
          <div className="p-6 bg-white border-b border-stone-100 flex items-center justify-between">
            <h2 className="text-2xl font-bold text-stone-800 flex items-center gap-2">
              <ShoppingBag className="text-orange-600" />
              Your Order
            </h2>
            <button onClick={onClose} className="p-2 hover:bg-stone-50 rounded-full transition-colors">
              <X className="h-6 w-6 text-stone-500" />
            </button>
          </div>

          {/* Items */}
          <div className="flex-1 overflow-y-auto p-6 space-y-6">
            {items.length === 0 ? (
              <div className="h-full flex flex-col items-center justify-center text-center">
                <div className="w-20 h-20 bg-stone-100 rounded-full flex items-center justify-center mb-4">
                  <ShoppingBag className="h-10 w-10 text-stone-300" />
                </div>
                <h3 className="text-lg font-bold text-stone-600">Your cart is empty</h3>
                <p className="text-stone-400 text-sm max-w-[15rem]">Looks like you haven't added any delicious items yet!</p>
                <button 
                  onClick={onClose}
                  className="mt-6 px-6 py-2 bg-orange-600 text-white font-bold rounded-full hover:bg-orange-700 transition-colors"
                >
                  Browse Menu
                </button>
              </div>
            ) : (
              <>
                {items.map(item => (
                  <div key={item.cartId} className="flex gap-4 p-4 bg-white rounded-2xl shadow-sm border border-stone-100">
                    <img src={item.image} alt={item.name} className="w-20 h-20 rounded-xl object-cover" />
                    <div className="flex-1 min-w-0">
                      <div className="flex justify-between items-start">
                        <h4 className="font-bold text-stone-800 truncate">{item.name}</h4>
                        <button onClick={() => onRemove(item.cartId)} className="text-stone-400 hover:text-rose-500">
                          <Trash2 className="h-4 w-4" />
                        </button>
                      </div>
                      {item.selectedModifiers.length > 0 && (
                        <p className="text-[11px] text-stone-400 mt-0.5">
                          {item.selectedModifiers.map(m => m.name).join(", ")}
                        </p>
                      )}
                      <div className="flex items-center justify-between mt-3">
                        <div className="flex items-center bg-stone-50 rounded-lg overflow-hidden border border-stone-200 scale-90 origin-left">
                          <button 
                            disabled={item.quantity <= 1}
                            onClick={() => onUpdateQuantity(item.cartId, -1)}
                            className="px-2 py-1 hover:bg-white"
                          >-</button>
                          <span className="px-2 font-bold text-sm">{item.quantity}</span>
                          <button 
                            onClick={() => onUpdateQuantity(item.cartId, 1)}
                            className="px-2 py-1 hover:bg-white"
                          >+</button>
                        </div>
                        <span className="font-bold text-orange-600">
                          ${((item.price + item.selectedModifiers.reduce((a, b) => a + b.price, 0)) * item.quantity).toFixed(2)}
                        </span>
                      </div>
                    </div>
                  </div>
                ))}

                {/* AI Upsell */}
                <div className="bg-orange-50 border border-orange-100 rounded-2xl p-4 flex gap-3 items-start">
                  <div className="p-2 bg-white rounded-xl shadow-sm">
                    <Sparkles className="h-5 w-5 text-orange-500 animate-pulse" />
                  </div>
                  <div>
                    <h5 className="text-xs font-bold text-orange-600 uppercase tracking-widest mb-1">Chef Suggests</h5>
                    <p className="text-stone-700 text-sm italic font-medium">
                      {loadingUpsell ? "Thinking..." : `"${upsell}"`}
                    </p>
                  </div>
                </div>
              </>
            )}
          </div>

          {/* Footer / Checkout */}
          {items.length > 0 && (
            <div className="p-6 bg-white border-t border-stone-100 space-y-4">
              <div className="flex p-1 bg-stone-100 rounded-xl">
                <button 
                  onClick={() => setDeliveryType('pickup')}
                  className={`flex-1 flex items-center justify-center gap-2 py-2 rounded-lg transition-all font-bold ${deliveryType === 'pickup' ? 'bg-white shadow-sm text-orange-600' : 'text-stone-500'}`}
                >
                  <ShoppingBag className="h-4 w-4" /> Pickup
                </button>
                <button 
                  onClick={() => setDeliveryType('delivery')}
                  className={`flex-1 flex items-center justify-center gap-2 py-2 rounded-lg transition-all font-bold ${deliveryType === 'delivery' ? 'bg-white shadow-sm text-orange-600' : 'text-stone-500'}`}
                >
                  <MapPin className="h-4 w-4" /> Delivery
                </button>
              </div>

              <div className="space-y-2">
                <div className="flex justify-between text-stone-500">
                  <span>Subtotal</span>
                  <span>${subtotal.toFixed(2)}</span>
                </div>
                {deliveryType === 'delivery' && (
                  <div className="flex justify-between text-stone-500">
                    <span>Delivery Fee</span>
                    <span>$4.99</span>
                  </div>
                )}
                <div className="flex justify-between text-xl font-bold text-stone-800 pt-2">
                  <span>Total</span>
                  <span className="text-orange-600">${total.toFixed(2)}</span>
                </div>
              </div>

              <button 
                onClick={() => onCheckout(deliveryType)}
                className="w-full bg-orange-600 hover:bg-orange-700 text-white font-bold py-4 rounded-2xl shadow-lg shadow-orange-200 transition-all active:scale-[0.98]"
              >
                Place {deliveryType === 'pickup' ? 'Pickup' : 'Delivery'} Order
              </button>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default Cart;

import React, { useState, useEffect, useMemo } from 'react';
import { MenuItem, Category, CartItem, Order, Modifier } from './types';
import { INITIAL_MENU } from './constants';
import Navbar from './components/Navbar';
import MenuCard from './components/MenuCard';
import Cart from './components/Cart';
import AdminDashboard from './components/AdminDashboard';
import { Search, MapPin, Phone, Instagram, Facebook, Twitter, ChefHat, Sparkles } from 'lucide-react';

const App: React.FC = () => {
  const [view, setView] = useState<'menu' | 'admin'>('menu');
  const [menu, setMenu] = useState<MenuItem[]>(() => {
    const saved = localStorage.getItem('la_cantina_menu');
    return saved ? JSON.parse(saved) : INITIAL_MENU;
  });
  const [cart, setCart] = useState<CartItem[]>([]);
  const [orders, setOrders] = useState<Order[]>(() => {
    const saved = localStorage.getItem('la_cantina_orders');
    return saved ? JSON.parse(saved) : [];
  });
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [activeCategory, setActiveCategory] = useState<Category | 'All'>('All');
  const [searchQuery, setSearchQuery] = useState('');

  // Persist menu and orders
  useEffect(() => {
    localStorage.setItem('la_cantina_menu', JSON.stringify(menu));
  }, [menu]);

  useEffect(() => {
    localStorage.setItem('la_cantina_orders', JSON.stringify(orders));
  }, [orders]);

  const categories: (Category | 'All')[] = ['All', 'Tacos', 'Burritos', 'Tortas', 'Sides', 'Drinks', 'Desserts', 'Specials'];

  const filteredMenu = useMemo(() => {
    return menu.filter(item => {
      const matchesCategory = activeCategory === 'All' || item.category === activeCategory;
      const matchesSearch = item.name.toLowerCase().includes(searchQuery.toLowerCase()) || 
                            item.description.toLowerCase().includes(searchQuery.toLowerCase());
      return matchesCategory && matchesSearch;
    });
  }, [menu, activeCategory, searchQuery]);

  const handleAddToCart = (item: MenuItem, modifiers: Modifier[], quantity: number) => {
    const cartId = `${item.id}-${modifiers.map(m => m.id).join('-')}-${Date.now()}`;
    const newItem: CartItem = {
      ...item,
      cartId,
      quantity,
      selectedModifiers: modifiers
    };
    setCart(prev => [...prev, newItem]);
    setIsCartOpen(true);
  };

  const handleRemoveFromCart = (cartId: string) => {
    setCart(prev => prev.filter(item => item.cartId !== cartId));
  };

  const handleUpdateCartQuantity = (cartId: string, delta: number) => {
    setCart(prev => prev.map(item => 
      item.cartId === cartId 
        ? { ...item, quantity: Math.max(1, item.quantity + delta) }
        : item
    ));
  };

  const handleCheckout = (deliveryType: 'pickup' | 'delivery') => {
    const subtotal = cart.reduce((acc, item) => {
      const modsTotal = item.selectedModifiers.reduce((sum, m) => sum + m.price, 0);
      return acc + (item.price + modsTotal) * item.quantity;
    }, 0);
    const total = subtotal + (deliveryType === 'delivery' ? 4.99 : 0);

    const newOrder: Order = {
      id: `ORD-${Math.random().toString(36).substr(2, 9).toUpperCase()}`,
      items: [...cart],
      total,
      status: 'pending',
      customerName: 'Guest Customer',
      deliveryType,
      timestamp: Date.now()
    };

    setOrders(prev => [...prev, newOrder]);
    setCart([]);
    setIsCartOpen(false);
    alert(`Order placed successfully! Reference: ${newOrder.id}`);
  };

  const handleUpdateOrderStatus = (orderId: string, status: Order['status']) => {
    setOrders(prev => prev.map(o => o.id === orderId ? { ...o, status } : o));
  };

  const handleDeleteMenu = (id: string) => {
    setMenu(prev => prev.filter(item => item.id !== id));
  };

  return (
    <div className="min-h-screen flex flex-col">
      <Navbar 
        onCartToggle={() => setIsCartOpen(!isCartOpen)} 
        cartCount={cart.reduce((acc, i) => acc + i.quantity, 0)}
        onViewChange={setView}
      />

      <main className="flex-1">
        {view === 'menu' ? (
          <div className="pb-20">
            {/* Hero Section */}
            <div className="relative h-[60vh] sm:h-[70vh] flex items-center justify-center overflow-hidden">
              <img 
                src="https://images.unsplash.com/photo-1504674900247-0877df9cc836?auto=format&fit=crop&q=80&w=1200" 
                className="absolute inset-0 w-full h-full object-cover"
                alt="Mexican Feast"
              />
              <div className="absolute inset-0 bg-gradient-to-t from-stone-900/90 via-stone-900/40 to-transparent" />

              <div className="relative z-10 text-center px-4 max-w-3xl">
                <div className="inline-flex items-center gap-2 bg-orange-500/90 backdrop-blur-sm text-white px-4 py-1.5 rounded-full text-xs font-bold uppercase tracking-widest mb-6">
                  <Sparkles className="h-4 w-4" />
                  Authentic Mexican Flavors
                </div>
                <h1 className="text-5xl sm:text-7xl font-bold text-white mb-6 mexican-font leading-tight">
                  Tacos, Burritos & <br/><span className="text-orange-400">Pure Joy.</span>
                </h1>
                <p className="text-lg sm:text-xl text-stone-200 mb-8 font-light max-w-2xl mx-auto">
                  Experience the bold flavors of Mexico City delivered straight to your door or ready for pickup.
                </p>
                <div className="flex flex-col sm:flex-row gap-4 justify-center">
                  <button 
                    onClick={() => {
                      const el = document.getElementById('menu-start');
                      el?.scrollIntoView({ behavior: 'smooth' });
                    }}
                    className="px-8 py-4 bg-orange-600 hover:bg-orange-700 text-white font-bold rounded-2xl shadow-xl shadow-orange-900/20 transition-all active:scale-95"
                  >
                    Explore Our Menu
                  </button>
                  <button 
                    className="px-8 py-4 bg-white/10 hover:bg-white/20 backdrop-blur-md text-white font-bold rounded-2xl border border-white/20 transition-all"
                  >
                    Special Offers
                  </button>
                </div>
              </div>
            </div>

            {/* Menu Controls */}
            <div id="menu-start" className="sticky top-16 z-40 bg-white/80 backdrop-blur-lg border-b border-stone-100 py-4 shadow-sm">
              <div className="max-w-7xl mx-auto px-4">
                <div className="flex flex-col md:flex-row gap-4 items-center justify-between">
                  <div className="flex gap-2 overflow-x-auto w-full md:w-auto pb-2 md:pb-0 no-scrollbar">
                    {categories.map(cat => (
                      <button 
                        key={cat}
                        onClick={() => setActiveCategory(cat)}
                        className={`px-5 py-2 rounded-xl text-sm font-bold whitespace-nowrap transition-all ${
                          activeCategory === cat 
                            ? 'bg-orange-600 text-white shadow-lg shadow-orange-200' 
                            : 'bg-stone-100 text-stone-500 hover:bg-stone-200'
                        }`}
                      >
                        {cat}
                      </button>
                    ))}
                  </div>
                  <div className="relative w-full md:w-64">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-stone-400" />
                    <input 
                      type="text" 
                      placeholder="Search menu..."
                      value={searchQuery}
                      onChange={(e) => setSearchQuery(e.target.value)}
