import React, { useState } from 'react';
import { MenuItem, Modifier } from '../types';
import { Plus, X, ChevronRight, Check, MessageSquare } from 'lucide-react';

interface MenuCardProps {
  item: MenuItem;
  onAddToCart: (item: MenuItem, modifiers: Modifier[], quantity: number, instructions: string) => void;
}

const MenuCard: React.FC<MenuCardProps> = ({ item, onAddToCart }) => {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [selectedMods, setSelectedMods] = useState<Modifier[]>([]);
  const [quantity, setQuantity] = useState(1);
  const [instructions, setInstructions] = useState('');

  const handleToggleMod = (mod: Modifier) => {
    setSelectedMods(prev => 
      prev.find(m => m.id === mod.id)
        ? prev.filter(m => m.id !== mod.id)
        : [...prev, mod]
    );
  };

  const handleAdd = () => {
    onAddToCart(item, selectedMods, quantity, instructions);
    setIsModalOpen(false);
    setSelectedMods([]);
    setQuantity(1);
    setInstructions('');
  };

  const totalPrice = item.price + selectedMods.reduce((acc, curr) => acc + curr.price, 0);

  return (
    <>
      <div 
        onClick={() => setIsModalOpen(true)}
        className="group bg-white rounded-2xl overflow-hidden shadow-sm hover:shadow-xl hover:-translate-y-1 transition-all duration-300 cursor-pointer border border-stone-100 flex flex-col h-full"
      >
        <div className="relative h-48 sm:h-52 overflow-hidden">
          <img 
            src={item.image} 
            alt={item.name} 
            className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-700"
          />
          <div className="absolute top-3 right-3 bg-white/95 backdrop-blur-sm px-3 py-1.5 rounded-full text-sm font-bold text-orange-600 shadow-lg">
            ${item.price.toFixed(2)}
          </div>
          <div className="absolute inset-0 bg-gradient-to-t from-black/20 to-transparent opacity-0 group-hover:opacity-100 transition-opacity" />
        </div>
        <div className="p-5 flex flex-col flex-1">
          <div className="mb-2">
            <span className="text-[10px] font-black uppercase tracking-widest text-orange-500 bg-orange-50 px-2 py-0.5 rounded-md">
              {item.category}
            </span>
          </div>
          <h3 className="text-xl font-bold text-stone-800 mb-2 leading-tight">{item.name}</h3>
          <p className="text-stone-500 text-sm line-clamp-2 mb-4 leading-relaxed flex-1">
            {item.description}
          </p>
          <div className="flex items-center justify-between mt-auto pt-4 border-t border-stone-50">
            <span className="text-orange-600 font-bold">Customize</span>
            <div className="p-2 bg-orange-600 text-white rounded-xl shadow-md group-hover:bg-orange-700 transition-colors">
              <Plus className="h-5 w-5" />
            </div>
          </div>
        </div>
      </div>

      {isModalOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-0 sm:p-4 bg-stone-900/60 backdrop-blur-md transition-all">
          <div className="bg-white rounded-none sm:rounded-[2.5rem] w-full max-w-2xl h-full sm:h-auto max-h-screen sm:max-h-[90vh] overflow-hidden shadow-2xl flex flex-col animate-in fade-in zoom-in duration-300">

            {/* Header / Image Area */}
            <div className="relative h-48 sm:h-72 shrink-0">
              <img src={item.image} alt={item.name} className="w-full h-full object-cover" />
              <div className="absolute inset-0 bg-gradient-to-t from-white via-transparent to-black/30" />
              <button 
                onClick={() => setIsModalOpen(false)}
                className="absolute top-6 right-6 p-3 bg-white/20 hover:bg-white/40 backdrop-blur-md rounded-full text-white transition-all hover:rotate-90"
              >
                <X className="h-6 w-6" />
              </button>
              <div className="absolute bottom-6 left-8 right-8">
                <h2 className="text-3xl sm:text-4xl font-bold text-stone-800 drop-shadow-sm">{item.name}</h2>
              </div>
            </div>

            <div className="flex-1 overflow-y-auto p-6 sm:p-8 custom-scrollbar">
              <p className="text-stone-500 text-lg mb-8 leading-relaxed">{item.description}</p>

              {item.availableModifiers.length > 0 && (
                <div className="mb-10">
                  <div className="flex items-center justify-between mb-5">
                    <h4 className="text-sm font-black text-stone-400 uppercase tracking-[0.2em]">Personalize your dish</h4>
                    <span className="text-xs text-stone-400 font-medium italic">Optional extras</span>
                  </div>
                  <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                    {item.availableModifiers.map(mod => {
                      const isSelected = selectedMods.some(m => m.id === mod.id);
                      return (
                        <button 
                          key={mod.id}
                          onClick={() => handleToggleMod(mod)}
                          className={`flex items-center justify-between p-4 rounded-2xl border-2 transition-all text-left group ${
                            isSelected 
                              ? 'border-orange-500 bg-orange-50 shadow-sm' 
                              : 'border-stone-100 hover:border-orange-200 hover:bg-stone-50'
                          }`}
                        >
                          <div className="flex items-center gap-3">
