            {/* Actions Bar */}
            <div className="p-6 sm:p-8 bg-white border-t border-stone-100 flex flex-col sm:flex-row items-center gap-6 shrink-0 shadow-[0_-10px_40px_-15px_rgba(0,0,0,0.05)]">
              <div className="flex items-center bg-stone-100 p-1.5 rounded-2xl">
                <button 
                  disabled={quantity <= 1}
                  onClick={() => setQuantity(q => q - 1)}
                  className="w-12 h-12 flex items-center justify-center bg-white rounded-xl shadow-sm text-xl font-bold hover:bg-stone-50 disabled:opacity-30 disabled:hover:bg-white transition-all active:scale-90"
                >-</button>
                <span className="px-6 font-black text-lg min-w-[3.5rem] text-center text-stone-800">{quantity}</span>
                <button 
                  onClick={() => setQuantity(q => q + 1)}
                  className="w-12 h-12 flex items-center justify-center bg-white rounded-xl shadow-sm text-xl font-bold hover:bg-stone-50 transition-all active:scale-90"
                >+</button>
              </div>
              <button 
                onClick={handleAdd}
                className="w-full sm:flex-1 bg-orange-600 hover:bg-orange-700 text-white font-black text-lg py-4.5 px-8 rounded-2xl shadow-xl shadow-orange-200 flex items-center justify-center gap-3 transition-all active:scale-95 group"
              >
                Add to Order — ${(totalPrice * quantity).toFixed(2)}
                <ChevronRight className="h-6 w-6 group-hover:translate-x-1 transition-transform" />
              </button>
            </div>
          </div>
        </div>
      )}
    </>
  );
};

