import React, { useEffect, useState } from 'react';
import { CartItem, MenuItem } from '../types';
import { X, Trash2, Sparkles, MapPin, ShoppingBag, MessageSquare } from 'lucide-react';
import { getUpsellSuggestions } from '../services/geminiService';

interface CartProps {
  isOpen: boolean;
  onClose: () => void;
  items: CartItem[];
  onRemove: (cartId: string) => void;
  onUpdateQuantity: (cartId: string, delta: number) => void;
  onCheckout: (deliveryType: 'pickup' | 'delivery') => void;
  menu: MenuItem[];
}

const Cart: React.FC<CartProps> = ({ isOpen, onClose, items, onRemove, onUpdateQuantity, onCheckout, menu }) => {
  const [upsell, setUpsell] = useState<string>("");
  const [loadingUpsell, setLoadingUpsell] = useState(false);
  const [deliveryType, setDeliveryType] = useState<'pickup' | 'delivery'>('pickup');

  useEffect(() => {
    if (isOpen && items.length > 0) {
      setLoadingUpsell(true);
      getUpsellSuggestions(items, menu).then(suggestion => {
        setUpsell(suggestion);
        setLoadingUpsell(false);
      });
    }
  }, [isOpen, items.length]);

  const subtotal = items.reduce((acc, item) => {
    const modsTotal = item.selectedModifiers.reduce((sum, m) => sum + m.price, 0);
    return acc + (item.price + modsTotal) * item.quantity;
  }, 0);

  const deliveryFee = deliveryType === 'delivery' ? 4.99 : 0;
  const total = subtotal + deliveryFee;

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-[110] overflow-hidden">
      <div className="absolute inset-0 bg-stone-900/40 backdrop-blur-sm" onClick={onClose} />
      <div className="absolute right-0 top-0 h-full w-full max-w-md bg-stone-50 shadow-2xl animate-in slide-in-from-right duration-300">
        <div className="flex flex-col h-full">
          {/* Header */}
          <div className="p-6 bg-white border-b border-stone-100 flex items-center justify-between">
            <h2 className="text-2xl font-bold text-stone-800 flex items-center gap-2">
              <ShoppingBag className="text-orange-600" />
              Your Order
            </h2>
            <button onClick={onClose} className="p-2 hover:bg-stone-50 rounded-full transition-colors">
              <X className="h-6 w-6 text-stone-500" />
            </button>
          </div>

          {/* Items */}
          <div className="flex-1 overflow-y-auto p-6 space-y-6">
            {items.length === 0 ? (
              <div className="h-full flex flex-col items-center justify-center text-center">
                <div className="w-20 h-20 bg-stone-100 rounded-full flex items-center justify-center mb-4">
                  <ShoppingBag className="h-10 w-10 text-stone-300" />
                </div>
                <h3 className="text-lg font-bold text-stone-600">Your cart is empty</h3>
                <p className="text-stone-400 text-sm max-w-[15rem]">Looks like you haven't added any delicious items yet!</p>
                <button 
                  onClick={onClose}
                  className="mt-6 px-6 py-2 bg-orange-600 text-white font-bold rounded-full hover:bg-orange-700 transition-colors"
                >
                  Browse Menu
                </button>
              </div>
            ) : (
              <>
                {items.map(item => (
                  <div key={item.cartId} className="flex gap-4 p-4 bg-white rounded-2xl shadow-sm border border-stone-100">
                    <img src={item.image} alt={item.name} className="w-20 h-20 rounded-xl object-cover" />
                    <div className="flex-1 min-w-0">
                      <div className="flex justify-between items-start">
                        <h4 className="font-bold text-stone-800 truncate">{item.name}</h4>
                        <button onClick={() => onRemove(item.cartId)} className="text-stone-400 hover:text-rose-500">
                          <Trash2 className="h-4 w-4" />
                        </button>
                      </div>
                      <div className="mt-0.5 space-y-1">
                        {item.selectedModifiers.length > 0 && (
                          <p className="text-[11px] text-stone-400 leading-tight">
                            {item.selectedModifiers.map(m => m.name).join(", ")}
                          </p>
                        )}
                        {item.specialInstructions && (
                          <p className="text-[10px] text-stone-500 italic flex items-center gap-1">
                            <MessageSquare className="h-3 w-3" />
                            "{item.specialInstructions}"
                          </p>
                        )}
                      </div>
                      <div className="flex items-center justify-between mt-3">
                        <div className="flex items-center bg-stone-50 rounded-lg overflow-hidden border border-stone-200 scale-90 origin-left">
                          <button 
                            disabled={item.quantity <= 1}
                            onClick={() => onUpdateQuantity(item.cartId, -1)}
                            className="px-2 py-1 hover:bg-white"
                          >-</button>
                          <span className="px-2 font-bold text-sm">{item.quantity}</span>
                          <button 
                            onClick={() => onUpdateQuantity(item.cartId, 1)}
                            className="px-2 py-1 hover:bg-white"
                          >+</button>
                        </div>
                        <span className="font-bold text-orange-600">
                          ${((item.price + item.selectedModifiers.reduce((a, b) => a + b.price, 0)) * item.quantity).toFixed(2)}
                        </span>
                      </div>
                    </div>
                  </div>
                ))}

                {/* AI Upsell */}
                <div className="bg-orange-50 border border-orange-100 rounded-2xl p-4 flex gap-3 items-start">
                  <div className="p-2 bg-white rounded-xl shadow-sm">
                    <Sparkles className="h-5 w-5 text-orange-500 animate-pulse" />
                  </div>
                  <div>
                    <h5 className="text-xs font-bold text-orange-600 uppercase tracking-widest mb-1">Chef Suggests</h5>
                    <p className="text-stone-700 text-sm italic font-medium leading-relaxed">
                      {loadingUpsell ? "Thinking..." : `"${upsell}"`}
                    </p>
                  </div>
                </div>
              </>
            )}
          </div>

          {/* Footer / Checkout */}
          {items.length > 0 && (
            <div className="p-6 bg-white border-t border-stone-100 space-y-4">
              <div className="flex p-1 bg-stone-100 rounded-xl">
                <button 
                  onClick={() => setDeliveryType('pickup')}
