import React, { useState, useEffect, useMemo } from 'react';
import { MenuItem, Category, CartItem, Order, Modifier } from './types';
import { INITIAL_MENU } from './constants';
import MenuCard from './components/MenuCard';
import Cart from './components/Cart';
import AdminDashboard from './components/AdminDashboard';
import { Search, ShoppingBag, User, Utensils, Sparkles, ChefHat } from 'lucide-react';

const App: React.FC = () => {
  const [view, setView] = useState<'menu' | 'admin'>('menu');
  const [menu, setMenu] = useState<MenuItem[]>(() => {
    const saved = localStorage.getItem('la_cantina_menu');
    return saved ? JSON.parse(saved) : INITIAL_MENU;
  });
  const [cart, setCart] = useState<CartItem[]>([]);
  const [orders, setOrders] = useState<Order[]>(() => {
    const saved = localStorage.getItem('la_cantina_orders');
    return saved ? JSON.parse(saved) : [];
  });
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [activeCategory, setActiveCategory] = useState<Category | 'All'>('All');
  const [searchQuery, setSearchQuery] = useState('');

  // Persist menu and orders
  useEffect(() => {
    localStorage.setItem('la_cantina_menu', JSON.stringify(menu));
  }, [menu]);

  useEffect(() => {
    localStorage.setItem('la_cantina_orders', JSON.stringify(orders));
  }, [orders]);

  const categories: (Category | 'All')[] = ['All', 'Tacos', 'Burritos', 'Tortas', 'Sides', 'Drinks', 'Desserts', 'Specials'];

  const filteredMenu = useMemo(() => {
    return menu.filter(item => {
      const matchesCategory = activeCategory === 'All' || item.category === activeCategory;
      const matchesSearch = item.name.toLowerCase().includes(searchQuery.toLowerCase()) || 
                            item.description.toLowerCase().includes(searchQuery.toLowerCase());
      return matchesCategory && matchesSearch;
    });
  }, [menu, activeCategory, searchQuery]);

  const handleAddToCart = (item: MenuItem, modifiers: Modifier[], quantity: number, instructions: string) => {
    const cartId = `${item.id}-${modifiers.map(m => m.id).join('-')}-${Date.now()}`;
    const newItem: CartItem = {
      ...item,
      cartId,
      quantity,
      selectedModifiers: modifiers,
      specialInstructions: instructions
    };
    setCart(prev => [...prev, newItem]);
    setIsCartOpen(true);
  };

  const handleRemoveFromCart = (cartId: string) => {
    setCart(prev => prev.filter(item => item.cartId !== cartId));
  };

  const handleUpdateCartQuantity = (cartId: string, delta: number) => {
    setCart(prev => prev.map(item => 
      item.cartId === cartId 
        ? { ...item, quantity: Math.max(1, item.quantity + delta) }
        : item
    ));
  };

  const handleCheckout = (deliveryType: 'pickup' | 'delivery') => {
    const subtotal = cart.reduce((acc, item) => {
      const modsTotal = item.selectedModifiers.reduce((sum, m) => sum + m.price, 0);
      return acc + (item.price + modsTotal) * item.quantity;
    }, 0);
    const total = subtotal + (deliveryType === 'delivery' ? 4.99 : 0);

    const newOrder: Order = {
      id: `ORD-${Math.random().toString(36).substr(2, 9).toUpperCase()}`,
      items: [...cart],
      total,
      status: 'pending',
      customerName: 'Guest Customer',
      deliveryType,
      timestamp: Date.now()
    };

    setOrders(prev => [...prev, newOrder]);
    setCart([]);
    setIsCartOpen(false);
    alert(`Order placed successfully! Reference: ${newOrder.id}`);
  };

  const handleUpdateOrderStatus = (orderId: string, status: Order['status']) => {
    setOrders(prev => prev.map(o => o.id === orderId ? { ...o, status } : o));
  };

  const handleDeleteMenu = (id: string) => {
    setMenu(prev => prev.filter(item => item.id !== id));
  };

  const cartCount = cart.reduce((acc, i) => acc + i.quantity, 0);

  return (
    <div className="min-h-screen bg-stone-50 flex flex-col relative">
      {/* Floating View Toggle */}
      <div className="fixed top-6 left-6 z-50 flex gap-2">
        <button 
          onClick={() => setView(view === 'menu' ? 'admin' : 'menu')}
          className="bg-white/80 backdrop-blur-md p-3 rounded-2xl shadow-xl border border-stone-200 text-stone-700 hover:bg-orange-600 hover:text-white transition-all group"
        >
          {view === 'menu' ? <User className="h-5 w-5" /> : <Utensils className="h-5 w-5" />}
          <span className="max-w-0 overflow-hidden group-hover:max-w-xs transition-all duration-300 ml-0 group-hover:ml-2 font-bold whitespace-nowrap">
            {view === 'menu' ? 'Admin Dashboard' : 'Back to Menu'}
          </span>
        </button>
      </div>

      {/* Floating Cart Button */}
      <button 
        onClick={() => setIsCartOpen(true)}
        className="fixed bottom-8 right-8 z-50 bg-orange-600 text-white p-5 rounded-3xl shadow-2xl shadow-orange-200 hover:bg-orange-700 hover:scale-110 active:scale-95 transition-all flex items-center gap-3"
      >
        <ShoppingBag className="h-6 w-6" />
        {cartCount > 0 && (
          <span className="font-bold text-lg">{cartCount}</span>
        )}
      </button>

      <main className="flex-1">
        {view === 'menu' ? (
          <div className="pb-32">
            {/* Minimal Brand Identifier */}
            <div className="absolute top-6 right-6 z-50 flex items-center gap-2 bg-white/60 backdrop-blur-sm px-4 py-2 rounded-2xl border border-white/40 shadow-sm">
              <ChefHat className="text-orange-600 h-5 w-5" />
              <span className="font-bold text-stone-800 mexican-font">La Cantina</span>
            </div>

            {/* Hero Section */}
            <div className="relative h-[55vh] flex items-center justify-center overflow-hidden">
              <img 
                src="https://images.unsplash.com/photo-1504674900247-0877df9cc836?auto=format&fit=crop&q=80&w=1200" 
                className="absolute inset-0 w-full h-full object-cover"
                alt="Mexican Feast"
              />
              <div className="absolute inset-0 bg-gradient-to-t from-stone-50 via-stone-900/20 to-stone-900/40" />

              <div className="relative z-10 text-center px-4 max-w-3xl">
                <div className="inline-flex items-center gap-2 bg-orange-600 text-white px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-[0.2em] mb-6 shadow-xl shadow-orange-900/20">
                  <Sparkles className="h-3 w-3" />
                  Authentic Mexican
                </div>
                <h1 className="text-5xl sm:text-8xl font-black text-white mb-6 mexican-font drop-shadow-2xl">
                  Flavor of <span className="text-orange-400">Puebla</span>
                </h1>
                <p className="text-lg text-white/90 mb-8 font-medium max-w-xl mx-auto drop-shadow-md">
                  Handmade tortillas, slowly simmered meats, and recipes passed down through generations.
                </p>
              </div>
            </div>

            {/* Menu Controls */}
            <div className="sticky top-0 z-40 bg-stone-50/90 backdrop-blur-xl py-6">
              <div className="max-w-7xl mx-auto px-4">
                <div className="flex flex-col md:flex-row gap-6 items-center justify-between">
                  <div className="flex gap-2 overflow-x-auto w-full md:w-auto pb-2 md:pb-0 no-scrollbar">
                    {categories.map(cat => (
                      <button 
                        key={cat}
                        onClick={() => setActiveCategory(cat)}
                        className={`px-6 py-2.5 rounded-2xl text-xs font-black uppercase tracking-widest transition-all ${
                          activeCategory === cat 
                            ? 'bg-orange-600 text-white shadow-xl shadow-orange-200 scale-105' 
                            : 'bg-white text-stone-400 hover:text-stone-700 shadow-sm border border-stone-100'
                        }`}
                      >
                        {cat}
                      </button>
                    ))}
                  </div>
                  <div className="relative w-full md:w-80">
                    <Search className="absolute left-4 top-1/2 -translate-y-1/2 h-4 w-4 text-stone-300" />
                    <input 
                      type="text" 
                      placeholder="Find your favorite taco..."
                      value={searchQuery}
                      onChange={(e) => setSearchQuery(e.target.value)}
                      className="w-full pl-11 pr-5 py-3.5 bg-white border border-stone-100 rounded-[1.25rem] text-sm font-medium focus:ring-4 focus:ring-orange-500/10 focus:border-orange-200 transition-all shadow-sm"
                    />
                  </div>
                </div>
              </div>
            </div>

            {/* Menu Grid */}
            <div className="max-w-7xl mx-auto px-4 mt-4">
              <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-8">
                {filteredMenu.map(item => (
                  <MenuCard key={item.id} item={item} onAddToCart={handleAddToCart} />
                ))}
              </div>
              {filteredMenu.length === 0 && (
                <div className="py-32 text-center bg-white rounded-[3rem] border-2 border-dashed border-stone-200">
                  <div className="w-20 h-20 bg-stone-50 rounded-full flex items-center justify-center mx-auto mb-6">
                    <Search className="h-8 w-8 text-stone-200" />
                  </div>
                  <h3 className="text-2xl font-bold text-stone-400">No matches found</h3>
                  <p className="text-stone-300 font-medium">Try adjusting your filters or search terms</p>
                </div>
              )}
            </div>
          </div>
        ) : (
          <div className="pt-24 min-h-screen">
            <AdminDashboard 
              orders={orders} 
              menu={menu} 
              onUpdateStatus={handleUpdateOrderStatus}
              onUpdateMenu={(item) => setMenu(prev => prev.map(i => i.id === item.id ? item : i))}
              onDeleteMenu={handleDeleteMenu}
            />
          </div>
        )}
      </main>

      <Cart 
        isOpen={isCartOpen} 
        onClose={() => setIsCartOpen(false)} 
        items={cart}
        menu={menu}
        onRemove={handleRemoveFromCart}
        onUpdateQuantity={handleUpdateCartQuantity}
        onCheckout={handleCheckout}
      />
    </div>
  );
};

export default App;

import React, { useState, useRef } from 'react';
import { Order, MenuItem, Category } from '../types';
import { Trash2, Edit3, Package, TrendingUp, CheckCircle, Clock, Download, Upload, Plus } from 'lucide-react';

interface AdminDashboardProps {
  orders: Order[];
  menu: MenuItem[];
  onUpdateStatus: (orderId: string, status: Order['status']) => void;
  onUpdateMenu: (item: MenuItem) => void;
  onDeleteMenu: (id: string) => void;
  onBulkUpload: (items: MenuItem[]) => void;
}

const AdminDashboard: React.FC<AdminDashboardProps> = ({ orders, menu, onUpdateStatus, onUpdateMenu, onDeleteMenu, onBulkUpload }) => {
  const [activeTab, setActiveTab] = useState<'orders' | 'menu' | 'stats'>('orders');
  const fileInputRef = useRef<HTMLInputElement>(null);

  const totalSales = orders.reduce((acc, order) => order.status !== 'cancelled' ? acc + order.total : acc, 0);

  const downloadTemplate = () => {
    const headers = ['id', 'name', 'description', 'price', 'category', 'image'];
    const rows = menu.map(item => [
      item.id,
      item.name.replace(/,/g, ''),
      item.description.replace(/,/g, ''),
      item.price,
      item.category,
      item.image
    ]);

    const csvContent = [headers, ...rows].map(e => e.join(",")).join("\n");
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement("a");
    const url = URL.createObjectURL(blob);
    link.setAttribute("href", url);
    link.setAttribute("download", "la_cantina_menu_template.csv");
    link.style.visibility = 'hidden';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (e) => {
      const text = e.target?.result as string;
      const lines = text.split('\n');
      const headers = lines[0].split(',');

      const newItems: MenuItem[] = lines.slice(1).filter(line => line.trim()).map(line => {
        const values = line.split(',');
        return {
          id: values[0] || `new-${Math.random().toString(36).substr(2, 9)}`,
          name: values[1],
          description: values[2],
          price: parseFloat(values[3]),
          category: values[4] as Category,
          image: values[5],
          availableModifiers: [] // Simplified for CSV upload
        };
      });

      if (newItems.length > 0) {
        onBulkUpload(newItems);
        alert(`Successfully imported ${newItems.length} items!`);
      }
    };
    reader.readAsText(file);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  return (
    <div className="max-w-6xl mx-auto px-4 py-8">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center mb-8 gap-4">
        <div>
          <h1 className="text-4xl font-black text-stone-800 mexican-font tracking-tight">Manager Hub</h1>
          <p className="text-stone-500 font-medium">Control your digital kitchen and menu.</p>
        </div>
        <div className="flex gap-2 p-1.5 bg-stone-100 rounded-[1.5rem] w-full sm:w-auto">
          <button 
            onClick={() => setActiveTab('orders')}
            className={`flex-1 sm:flex-none px-6 py-2.5 rounded-2xl font-black text-xs uppercase tracking-widest flex items-center justify-center gap-2 transition-all ${activeTab === 'orders' ? 'bg-white shadow-md text-orange-600' : 'text-stone-400 hover:text-stone-600'}`}
          >
            <Package className="h-4 w-4" /> Orders
          </button>
          <button 
            onClick={() => setActiveTab('menu')}
            className={`flex-1 sm:flex-none px-6 py-2.5 rounded-2xl font-black text-xs uppercase tracking-widest flex items-center justify-center gap-2 transition-all ${activeTab === 'menu' ? 'bg-white shadow-md text-orange-600' : 'text-stone-400 hover:text-stone-600'}`}
          >
            <Edit3 className="h-4 w-4" /> Menu
          </button>
          <button 
            onClick={() => setActiveTab('stats')}
            className={`flex-1 sm:flex-none px-6 py-2.5 rounded-2xl font-black text-xs uppercase tracking-widest flex items-center justify-center gap-2 transition-all ${activeTab === 'stats' ? 'bg-white shadow-md text-orange-600' : 'text-stone-400 hover:text-stone-600'}`}
          >
            <TrendingUp className="h-4 w-4" /> Stats
          </button>
        </div>
      </div>

      {activeTab === 'orders' && (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
          {orders.length === 0 ? (
            <div className="col-span-full py-32 text-center bg-white rounded-[3rem] border-2 border-dashed border-stone-200">
              <Clock className="h-16 w-16 text-stone-200 mx-auto mb-6" />
              <h3 className="text-2xl font-bold text-stone-400">No active orders</h3>
              <p className="text-stone-300">Wait for hungry customers to start ordering!</p>
            </div>
          ) : (
            orders.slice().reverse().map(order => (
              <div key={order.id} className="bg-white rounded-[2rem] p-6 shadow-sm border border-stone-100 hover:shadow-xl transition-all duration-300">
                <div className="flex justify-between items-start mb-6">
                  <div>
                    <span className="text-[10px] font-black text-stone-400 uppercase tracking-widest">Order #{order.id.slice(-4)}</span>
                    <h3 className="font-bold text-xl text-stone-800 mt-1">{order.customerName}</h3>
                  </div>
                  <div className={`px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest ${
                    order.status === 'pending' ? 'bg-amber-100 text-amber-700' :
                    order.status === 'preparing' ? 'bg-blue-100 text-blue-700' :
                    order.status === 'ready' ? 'bg-emerald-100 text-emerald-700' :
                    order.status === 'delivered' ? 'bg-stone-100 text-stone-500' :
                    'bg-rose-100 text-rose-700'
                  }`}>
                    {order.status}
                  </div>
                </div>
                <div className="space-y-3 mb-8">
                  {order.items.map(item => (
                    <div key={item.cartId} className="flex justify-between items-center text-sm">
                      <div className="flex items-center gap-3">
                        <span className="w-6 h-6 bg-stone-100 rounded-lg flex items-center justify-center font-bold text-stone-600 text-xs">{item.quantity}</span>
                        <span className="text-stone-600 font-medium">{item.name}</span>
                      </div>
                      <span className="font-bold text-stone-800">${(item.price * item.quantity).toFixed(2)}</span>
                    </div>
                  ))}
                </div>
                <div className="pt-6 border-t border-stone-50 flex flex-col gap-4">
                  <div className="flex justify-between items-center">
                    <span className="text-sm font-bold text-stone-400 uppercase tracking-widest">Total Price</span>
                    <span className="text-2xl font-black text-orange-600">${order.total.toFixed(2)}</span>
                  </div>
                  <div className="flex gap-2">
                    {order.status === 'pending' && (
                      <button 
                        onClick={() => onUpdateStatus(order.id, 'preparing')}
                        className="flex-1 bg-orange-600 hover:bg-orange-700 text-white font-black py-3.5 rounded-2xl text-xs uppercase tracking-widest transition-all shadow-lg shadow-orange-100"
                      >
                        Accept Order
                      </button>
                    )}
                    {order.status === 'preparing' && (
                      <button 
                        onClick={() => onUpdateStatus(order.id, 'ready')}
                        className="flex-1 bg-emerald-600 hover:bg-emerald-700 text-white font-black py-3.5 rounded-2xl text-xs uppercase tracking-widest transition-all shadow-lg shadow-emerald-100"
                      >
                        Mark Ready
                      </button>
                    )}
                    {order.status === 'ready' && (
                       <button 
                       onClick={() => onUpdateStatus(order.id, 'delivered')}
                       className="flex-1 bg-stone-800 hover:bg-stone-900 text-white font-black py-3.5 rounded-2xl text-xs uppercase tracking-widest transition-all"
                     >
                       Complete Order
                     </button>
                    )}
                    {(order.status === 'ready' || order.status === 'pending') && (
                      <button 
                        onClick={() => onUpdateStatus(order.id, 'cancelled')}
                        className="p-3.5 bg-stone-50 text-stone-400 hover:text-rose-500 hover:bg-rose-50 transition-all rounded-2xl"
                      >
                        <Trash2 className="h-5 w-5" />
                      </button>
                    )}
                  </div>
                </div>
              </div>
            ))
          )}
        </div>
      )}

      {activeTab === 'menu' && (
        <div className="space-y-6">
          <div className="flex flex-col sm:flex-row gap-4 justify-between items-stretch sm:items-center">
             <div className="flex gap-3">
                <button 
                  onClick={downloadTemplate}
                  className="flex-1 sm:flex-none flex items-center justify-center gap-2 bg-white text-stone-600 font-bold px-6 py-3 rounded-2xl border border-stone-200 hover:bg-stone-50 transition-all shadow-sm"
                >
                  <Download className="h-4 w-4" />
                  <span className="text-sm">Download Template</span>
                </button>
                <button 
                  onClick={() => fileInputRef.current?.click()}
                  className="flex-1 sm:flex-none flex items-center justify-center gap-2 bg-orange-600 text-white font-bold px-6 py-3 rounded-2xl hover:bg-orange-700 transition-all shadow-lg shadow-orange-100"
                >
                  <Upload className="h-4 w-4" />
                  <span className="text-sm">Upload Items</span>
                </button>
                <input 
                  type="file" 
                  ref={fileInputRef} 
                  onChange={handleFileUpload} 
                  accept=".csv" 
                  className="hidden" 
                />
             </div>
             <button className="flex items-center justify-center gap-2 bg-stone-800 text-white font-bold px-6 py-3 rounded-2xl hover:bg-stone-900 transition-all">
                <Plus className="h-4 w-4" />
                <span className="text-sm">Add New Item</span>
             </button>
          </div>

          <div className="bg-white rounded-[2.5rem] overflow-hidden shadow-sm border border-stone-100">
            <div className="overflow-x-auto">
              <table className="w-full text-left">
                <thead className="bg-stone-50/50">
                  <tr>
                    <th className="px-8 py-5 text-[10px] font-black text-stone-400 uppercase tracking-widest">Menu Item</th>
                    <th className="px-8 py-5 text-[10px] font-black text-stone-400 uppercase tracking-widest">Category</th>
                    <th className="px-8 py-5 text-[10px] font-black text-stone-400 uppercase tracking-widest">Price</th>
                    <th className="px-8 py-5 text-[10px] font-black text-stone-400 uppercase tracking-widest text-right">Actions</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-stone-100">
                  {menu.map(item => (
                    <tr key={item.id} className="hover:bg-orange-50/20 transition-colors">
                      <td className="px-8 py-6">
                        <div className="flex items-center gap-4">
                          <img src={item.image} alt={item.name} className="w-14 h-14 rounded-2xl object-cover shadow-sm" />
                          <div>
                            <p className="font-bold text-stone-800 text-lg leading-tight mb-1">{item.name}</p>
                            <p className="text-xs text-stone-400 font-medium truncate max-w-[250px]">{item.description}</p>
                          </div>
                        </div>
                      </td>
                      <td className="px-8 py-6">
                        <span className="px-3 py-1 bg-stone-100 rounded-lg text-[10px] font-black text-stone-500 uppercase tracking-wider">{item.category}</span>
                      </td>
                      <td className="px-8 py-6 font-black text-stone-800 text-lg">${item.price.toFixed(2)}</td>
                      <td className="px-8 py-6 text-right">
                        <div className="flex justify-end gap-3">
                          <button className="p-2.5 text-stone-300 hover:text-orange-500 hover:bg-orange-50 rounded-xl transition-all"><Edit3 className="h-5 w-5" /></button>
                          <button onClick={() => onDeleteMenu(item.id)} className="p-2.5 text-stone-300 hover:text-rose-500 hover:bg-rose-50 rounded-xl transition-all"><Trash2 className="h-5 w-5" /></button>
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>

          <div className="p-10 text-center bg-stone-100 rounded-[2.5rem] border-2 border-dashed border-stone-200">
             <div className="max-w-md mx-auto">
                <Upload className="h-10 w-10 text-stone-300 mx-auto mb-4" />
                <h4 className="text-xl font-bold text-stone-700 mb-2">Need to update everything?</h4>
                <p className="text-stone-500 text-sm mb-6">Use our bulk upload tool at the top to sync your entire menu from a spreadsheet in seconds.</p>
                <button 
                  onClick={() => fileInputRef.current?.click()}
                  className="inline-flex items-center gap-2 bg-white text-stone-800 font-bold px-6 py-3 rounded-2xl border border-stone-200 hover:bg-stone-50 transition-all"
                >
                  Choose CSV File
                </button>
             </div>
          </div>
        </div>
      )}

      {activeTab === 'stats' && (
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-8">
          <div className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-stone-100">
            <p className="text-stone-400 text-[10px] font-black uppercase tracking-[0.2em] mb-4">Gross Revenue</p>
            <h4 className="text-4xl font-black text-emerald-600">${totalSales.toFixed(2)}</h4>
            <div className="mt-6 flex items-center gap-2 text-xs font-bold text-emerald-500 bg-emerald-50 px-3 py-1.5 rounded-full w-fit">
              <TrendingUp className="h-3 w-3" /> +12.5% vs last week
            </div>
          </div>
          <div className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-stone-100">
            <p className="text-stone-400 text-[10px] font-black uppercase tracking-[0.2em] mb-4">Total Orders</p>
            <h4 className="text-4xl font-black text-stone-800">{orders.length}</h4>
            <div className="mt-6 text-xs text-stone-400 font-medium">Kitchen efficiency: <span className="text-stone-800 font-bold">High</span></div>
          </div>
          <div className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-stone-100">
            <p className="text-stone-400 text-[10px] font-black uppercase tracking-[0.2em] mb-4">Top Seller</p>
            <h4 className="text-4xl font-black text-orange-600">Al Pastor</h4>
            <div className="mt-6 text-xs text-stone-400 font-medium">Contribution: <span className="text-stone-800 font-bold">24%</span></div>
          </div>
          <div className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-stone-100">
            <p className="text-stone-400 text-[10px] font-black uppercase tracking-[0.2em] mb-4">Rating</p>
            <h4 className="text-4xl font-black text-amber-500">4.9/5</h4>
            <div className="mt-6 flex items-center gap-2 text-xs font-bold text-amber-500 bg-amber-50 px-3 py-1.5 rounded-full w-fit">
              <CheckCircle className="h-3 w-3" /> 100% verified orders
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminDashboard;

import React, { useState, useEffect, useMemo } from 'react';
import { MenuItem, Category, CartItem, Order, Modifier } from './types';
import { INITIAL_MENU } from './constants';
import MenuCard from './components/MenuCard';
import Cart from './components/Cart';
import AdminDashboard from './components/AdminDashboard';
import { Search, ShoppingBag, User, Utensils, Sparkles, ChefHat } from 'lucide-react';

const App: React.FC = () => {
  const [view, setView] = useState<'menu' | 'admin'>('menu');
  const [menu, setMenu] = useState<MenuItem[]>(() => {
    const saved = localStorage.getItem('la_cantina_menu');
    return saved ? JSON.parse(saved) : INITIAL_MENU;
  });
  const [cart, setCart] = useState<CartItem[]>([]);
  const [orders, setOrders] = useState<Order[]>(() => {
    const saved = localStorage.getItem('la_cantina_orders');
    return saved ? JSON.parse(saved) : [];
  });
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [activeCategory, setActiveCategory] = useState<Category | 'All'>('All');
  const [searchQuery, setSearchQuery] = useState('');

  // Persist menu and orders
  useEffect(() => {
    localStorage.setItem('la_cantina_menu', JSON.stringify(menu));
  }, [menu]);

  useEffect(() => {
    localStorage.setItem('la_cantina_orders', JSON.stringify(orders));
  }, [orders]);

  const categories: (Category | 'All')[] = ['All', 'Tacos', 'Burritos', 'Tortas', 'Sides', 'Drinks', 'Desserts', 'Specials'];

  const filteredMenu = useMemo(() => {
    return menu.filter(item => {
      const matchesCategory = activeCategory === 'All' || item.category === activeCategory;
      const matchesSearch = item.name.toLowerCase().includes(searchQuery.toLowerCase()) || 
                            item.description.toLowerCase().includes(searchQuery.toLowerCase());
      return matchesCategory && matchesSearch;
    });
  }, [menu, activeCategory, searchQuery]);

  const handleAddToCart = (item: MenuItem, modifiers: Modifier[], quantity: number, instructions: string) => {
    const cartId = `${item.id}-${modifiers.map(m => m.id).join('-')}-${Date.now()}`;
    const newItem: CartItem = {
      ...item,
      cartId,
      quantity,
      selectedModifiers: modifiers,
      specialInstructions: instructions
    };
    setCart(prev => [...prev, newItem]);
    setIsCartOpen(true);
  };

  const handleRemoveFromCart = (cartId: string) => {
    setCart(prev => prev.filter(item => item.cartId !== cartId));
  };

  const handleUpdateCartQuantity = (cartId: string, delta: number) => {
    setCart(prev => prev.map(item => 
      item.cartId === cartId 
        ? { ...item, quantity: Math.max(1, item.quantity + delta) }
        : item
    ));
  };

  const handleCheckout = (deliveryType: 'pickup' | 'delivery') => {
    const subtotal = cart.reduce((acc, item) => {
      const modsTotal = item.selectedModifiers.reduce((sum, m) => sum + m.price, 0);
      return acc + (item.price + modsTotal) * item.quantity;
    }, 0);
    const total = subtotal + (deliveryType === 'delivery' ? 4.99 : 0);

    const newOrder: Order = {
      id: `ORD-${Math.random().toString(36).substr(2, 9).toUpperCase()}`,
      items: [...cart],
      total,
      status: 'pending',
      customerName: 'Guest Customer',
      deliveryType,
      timestamp: Date.now()
    };

    setOrders(prev => [...prev, newOrder]);
    setCart([]);
    setIsCartOpen(false);
    alert(`Order placed successfully! Reference: ${newOrder.id}`);
  };

  const handleUpdateOrderStatus = (orderId: string, status: Order['status']) => {
    setOrders(prev => prev.map(o => o.id === orderId ? { ...o, status } : o));
  };

  const handleDeleteMenu = (id: string) => {
    setMenu(prev => prev.filter(item => item.id !== id));
  };

  const handleBulkUpload = (newItems: MenuItem[]) => {
    // We update existing items by ID or add new ones
    setMenu(prev => {
      const existingIds = new Set(prev.map(item => item.id));
      const filteredNew = newItems.filter(item => !existingIds.has(item.id));
      const updatedPrev = prev.map(item => {
        const matchingNew = newItems.find(newItem => newItem.id === item.id);
        return matchingNew ? { ...matchingNew, availableModifiers: item.availableModifiers } : item;
      });
      return [...updatedPrev, ...filteredNew];
    });
  };

  const cartCount = cart.reduce((acc, i) => acc + i.quantity, 0);

  return (
    <div className="min-h-screen bg-stone-50 flex flex-col relative">
      {/* Floating View Toggle */}
      <div className="fixed top-6 left-6 z-50 flex gap-2">
        <button 
          onClick={() => setView(view === 'menu' ? 'admin' : 'menu')}
          className="bg-white/80 backdrop-blur-md p-3 rounded-2xl shadow-xl border border-stone-200 text-stone-700 hover:bg-orange-600 hover:text-white transition-all group"
        >
          {view === 'menu' ? <User className="h-5 w-5" /> : <Utensils className="h-5 w-5" />}
          <span className="max-w-0 overflow-hidden group-hover:max-w-xs transition-all duration-300 ml-0 group-hover:ml-2 font-bold whitespace-nowrap">
            {view === 'menu' ? 'Admin Dashboard' : 'Back to Menu'}
          </span>
        </button>
      </div>

      {/* Floating Cart Button */}
      <button 
        onClick={() => setIsCartOpen(true)}
        className="fixed bottom-8 right-8 z-50 bg-orange-600 text-white p-5 rounded-3xl shadow-2xl shadow-orange-200 hover:bg-orange-700 hover:scale-110 active:scale-95 transition-all flex items-center gap-3"
      >
        <ShoppingBag className="h-6 w-6" />
        {cartCount > 0 && (
          <span className="font-bold text-lg">{cartCount}</span>
        )}
      </button>

      <main className="flex-1">
        {view === 'menu' ? (
          <div className="pb-32">
            {/* Minimal Brand Identifier */}
            <div className="absolute top-6 right-6 z-50 flex items-center gap-2 bg-white/60 backdrop-blur-sm px-4 py-2 rounded-2xl border border-white/40 shadow-sm">
              <ChefHat className="text-orange-600 h-5 w-5" />
              <span className="font-bold text-stone-800 mexican-font">La Cantina</span>
            </div>

            {/* Hero Section */}
            <div className="relative h-[55vh] flex items-center justify-center overflow-hidden">
              <img 
                src="https://images.unsplash.com/photo-1504674900247-0877df9cc836?auto=format&fit=crop&q=80&w=1200" 
                className="absolute inset-0 w-full h-full object-cover"
                alt="Mexican Feast"
              />
              <div className="absolute inset-0 bg-gradient-to-t from-stone-50 via-stone-900/20 to-stone-900/40" />

              <div className="relative z-10 text-center px-4 max-w-3xl">
                <div className="inline-flex items-center gap-2 bg-orange-600 text-white px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-[0.2em] mb-6 shadow-xl shadow-orange-900/20">
                  <Sparkles className="h-3 w-3" />
                  Authentic Mexican
                </div>
                <h1 className="text-5xl sm:text-8xl font-black text-white mb-6 mexican-font drop-shadow-2xl">
                  Flavor of <span className="text-orange-400">Puebla</span>
                </h1>
                <p className="text-lg text-white/90 mb-8 font-medium max-w-xl mx-auto drop-shadow-md">
                  Handmade tortillas, slowly simmered meats, and recipes passed down through generations.
                </p>
              </div>
            </div>

            {/* Menu Controls */}
            <div className="sticky top-0 z-40 bg-stone-50/90 backdrop-blur-xl py-6">
              <div className="max-w-7xl mx-auto px-4">
                <div className="flex flex-col md:flex-row gap-6 items-center justify-between">
                  <div className="flex gap-2 overflow-x-auto w-full md:w-auto pb-2 md:pb-0 no-scrollbar">
                    {categories.map(cat => (
                      <button 
                        key={cat}
                        onClick={() => setActiveCategory(cat)}
                        className={`px-6 py-2.5 rounded-2xl text-xs font-black uppercase tracking-widest transition-all ${
                          activeCategory === cat 
                            ? 'bg-orange-600 text-white shadow-xl shadow-orange-200 scale-105' 
                            : 'bg-white text-stone-400 hover:text-stone-700 shadow-sm border border-stone-100'
                        }`}
                      >
                        {cat}
                      </button>
                    ))}
                  </div>
                  <div className="relative w-full md:w-80">
                    <Search className="absolute left-4 top-1/2 -translate-y-1/2 h-4 w-4 text-stone-300" />
                    <input 
                      type="text" 
                      placeholder="Find your favorite taco..."
                      value={searchQuery}
                      onChange={(e) => setSearchQuery(e.target.value)}
                      className="w-full pl-11 pr-5 py-3.5 bg-white border border-stone-100 rounded-[1.25rem] text-sm font-medium focus:ring-4 focus:ring-orange-500/10 focus:border-orange-200 transition-all shadow-sm"
                    />
                  </div>
                </div>
              </div>
            </div>

            {/* Menu Grid */}
            <div className="max-w-7xl mx-auto px-4 mt-4">
              <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-8">
                {filteredMenu.map(item => (
                  <MenuCard key={item.id} item={item} onAddToCart={handleAddToCart} />
                ))}
              </div>
              {filteredMenu.length === 0 && (
                <div className="py-32 text-center bg-white rounded-[3rem] border-2 border-dashed border-stone-200">
                  <div className="w-20 h-20 bg-stone-50 rounded-full flex items-center justify-center mx-auto mb-6">
                    <Search className="h-8 w-8 text-stone-200" />
                  </div>
                  <h3 className="text-2xl font-bold text-stone-400">No matches found</h3>
                  <p className="text-stone-300 font-medium">Try adjusting your filters or search terms</p>
                </div>
              )}
            </div>
          </div>
        ) : (
          <div className="pt-24 min-h-screen">
            <AdminDashboard 
              orders={orders} 
              menu={menu} 
              onUpdateStatus={handleUpdateOrderStatus}
              onUpdateMenu={(item) => setMenu(prev => prev.map(i => i.id === item.id ? item : i))}
              onDeleteMenu={handleDeleteMenu}
              onBulkUpload={handleBulkUpload}
            />
          </div>
        )}
      </main>

      <Cart 
        isOpen={isCartOpen} 
        onClose={() => setIsCartOpen(false)} 
        items={cart}
        menu={menu}
        onRemove={handleRemoveFromCart}
        onUpdateQuantity={handleUpdateCartQuantity}
        onCheckout={handleCheckout}
      />
    </div>
  );
};

export default App;
